/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 *
 * Supports per-channel settings via the `channelPreferences` map, which stores
 * enabled/categories for each non-email channel (SMS, webhook, etc.).
 * Email settings use the original top-level fields for backward compatibility.
 *
 * Design: opt-out for email (enabled by default), opt-in for SMS/webhook
 * (disabled by default, since they are more intrusive or require setup).
 * Quiet hours apply globally across all channels.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * Email delivery frequency.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Quiet hours configuration — notifications are suppressed during this window.
 * Hours are in 24-hour format (0–23).
 */
export interface QuietHours {
  /** Start hour (inclusive), 0–23. */
  start: number;
  /** End hour (exclusive), 0–23. */
  end: number;
}

/**
 * Per-channel notification preference (used for non-email channels).
 */
export interface ChannelPreference {
  /** Whether this channel is enabled. */
  enabled: boolean;
  /** Which notification categories the user wants on this channel. */
  categories: NotificationType[];
}

/**
 * User notification preferences.
 */
export interface UserPreferences {
  /** Unique preferences ID. */
  id: string;
  /** The user these preferences belong to. */
  userId: string;
  /** Global toggle for email notifications. */
  emailEnabled: boolean;
  /** Which notification categories the user wants to receive via email. */
  emailCategories: NotificationType[];
  /** How often email notifications should be delivered. */
  emailFrequency: EmailFrequency;
  /** Optional quiet hours — suppress notifications during this window (applies globally). */
  quietHours?: QuietHours;
  /** Per-channel preferences for non-email channels (sms, webhook, etc.). */
  channelPreferences: Partial<Record<NotificationChannel, ChannelPreference>>;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  emailEnabled?: boolean;
  emailCategories?: NotificationType[];
  emailFrequency?: EmailFrequency;
  quietHours?: QuietHours;
  channelPreferences?: Partial<Record<NotificationChannel, ChannelPreference>>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  emailEnabled?: boolean;
  emailCategories?: NotificationType[];
  emailFrequency?: EmailFrequency;
  quietHours?: QuietHours | null;
  channelPreferences?: Partial<Record<NotificationChannel, ChannelPreference>>;
}

