/**
 * Check whether a notification should be sent on a given channel.
 *
 * For 'email', delegates to shouldSendEmail() (uses legacy email fields).
 * For other channels, checks channelPreferences[channel].
 * Returns true if no preferences exist (opt-out model), or if the channel
 * has no explicit preference entry (non-email channels default to disabled,
 * so returns false unless explicitly enabled).
 *
 * Quiet hours apply globally across all channels.
 */
shouldSend(
  channel: NotificationChannel,
  userId: string,
  notificationType: NotificationType,
  now?: Date,
): boolean {
  if (channel === 'email') {
    return this.shouldSendEmail(userId, notificationType, now);
  }

  const prefs = this.repository.findByUserId(userId);

  // No preferences = default behavior. Non-email channels default to disabled.
  if (!prefs) {
    return false;
  }

  const channelPref = prefs.channelPreferences[channel];

  // No explicit preference for this channel = disabled (opt-in model for non-email)
  if (!channelPref) {
    this.logger.debug(`No preference for channel ${channel} for user ${userId}, defaulting to disabled`);
    return false;
  }

  // Channel toggle
  if (!channelPref.enabled) {
    this.logger.debug(`Channel ${channel} disabled for user ${userId}`);
    return false;
  }

  // Category check
  if (!channelPref.categories.includes(notificationType)) {
    this.logger.debug(
      `User ${userId} not subscribed to category ${notificationType} on channel ${channel}`,
    );
    return false;
  }

  // Quiet hours check (global)
  if (prefs.quietHours) {
    const currentHour = (now ?? new Date()).getHours();
    if (isInQuietHours(currentHour, prefs.quietHours.start, prefs.quietHours.end)) {
      this.logger.debug(`User ${userId} is in quiet hours`);
      return false;
    }
  }

  return true;
}

