describe('PreferencesService — multi-channel (shouldSend)', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('channelPreferences CRUD', () => {
    it('should create preferences with default empty channelPreferences', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });
      expect(prefs.channelPreferences).toEqual({});
    });

    it('should create preferences with custom channelPreferences', () => {
      const smsPref: ChannelPreference = {
        enabled: true,
        categories: ['order-confirmation', 'order-status-update'],
      };
      const prefs = service.createPreferences({
        userId: 'user-1',
        channelPreferences: { sms: smsPref },
      });
      expect(prefs.channelPreferences.sms).toEqual(smsPref);
    });

    it('should update channelPreferences without overwriting unrelated channels', () => {
      const smsPref: ChannelPreference = {
        enabled: true,
        categories: ['order-confirmation'],
      };
      service.createPreferences({
        userId: 'user-1',
        channelPreferences: { sms: smsPref },
      });

      const webhookPref: ChannelPreference = {
        enabled: true,
        categories: ['order-status-update'],
      };
      const updated = service.updatePreferences('user-1', {
        channelPreferences: { webhook: webhookPref },
      });

      expect(updated.channelPreferences.sms).toEqual(smsPref);
      expect(updated.channelPreferences.webhook).toEqual(webhookPref);
    });

    it('should reset channelPreferences to defaults', () => {
      service.createPreferences({
        userId: 'user-1',
        channelPreferences: {
          sms: { enabled: true, categories: ['welcome'] },
        },
      });
      const reset = service.resetToDefaults('user-1');
      expect(reset.channelPreferences).toEqual(DEFAULT_CHANNEL_PREFERENCES);
    });
  });

  describe('shouldSend — email channel (backward compat)', () => {
    it('should delegate email to shouldSendEmail', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(service.shouldSend('email', 'user-1', 'order-confirmation')).toBe(true);
    });

    it('should respect email disabled via shouldSend', () => {
      service.createPreferences({ userId: 'user-1', emailEnabled: false });
      expect(service.shouldSend('email', 'user-1', 'order-confirmation')).toBe(false);
    });
  });

  describe('shouldSend — SMS channel', () => {
    it('should return false when no preferences exist (opt-in model)', () => {
      expect(service.shouldSend('sms', 'user-unknown', 'order-confirmation')).toBe(false);
    });

    it('should return false when SMS not in channelPreferences', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when SMS is explicitly disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        channelPreferences: {
          sms: { enabled: false, categories: ALL_NOTIFICATION_CATEGORIES },
        },
      });
      expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(false);
    });

    it('should return true when SMS is enabled and category matches', () => {
      service.createPreferences({
        userId: 'user-1',
        channelPreferences: {
          sms: { enabled: true, categories: ['order-confirmation', 'order-status-update'] },
        },
      });
      expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(true);
    });

    it('should return false when SMS is enabled but category not subscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        channelPreferences: {
          sms: { enabled: true, categories: ['order-confirmation'] },
        },
      });
      expect(service.shouldSend('sms', 'user-1', 'welcome')).toBe(false);
    });

    it('should respect quiet hours for SMS', () => {
      service.createPreferences({
        userId: 'user-1',
        quietHours: { start: 22, end: 7 },
        channelPreferences: {
          sms: { enabled: true, categories: ALL_NOTIFICATION_CATEGORIES },
        },
      });

      const lateNight = new Date('2026-04-02T23:00:00');
      expect(service.shouldSend('sms', 'user-1', 'order-confirmation', lateNight)).toBe(false);

      const noon = new Date('2026-04-02T12:00:00');
      expect(service.shouldSend('sms', 'user-1', 'order-confirmation', noon)).toBe(true);
    });
  });

  describe('shouldSend — webhook channel', () => {
    it('should return false when no webhook preference exists', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(service.shouldSend('webhook', 'user-1', 'order-confirmation')).toBe(false);
    });

    it('should return true when webhook is enabled and category matches', () => {
      service.createPreferences({
        userId: 'user-1',
        channelPreferences: {
          webhook: { enabled: true, categories: ['order-confirmation'] },
        },
      });
      expect(service.shouldSend('webhook', 'user-1', 'order-confirmation')).toBe(true);
    });

    it('should respect quiet hours for webhook', () => {
      service.createPreferences({
        userId: 'user-1',
        quietHours: { start: 9, end: 17 },
        channelPreferences: {
          webhook: { enabled: true, categories: ALL_NOTIFICATION_CATEGORIES },
        },
      });

      const noon = new Date('2026-04-02T12:00:00');
      expect(service.shouldSend('webhook', 'user-1', 'order-confirmation', noon)).toBe(false);

      const evening = new Date('2026-04-02T20:00:00');
      expect(service.shouldSend('webhook', 'user-1', 'order-confirmation', evening)).toBe(true);
    });
  });

  describe('shouldSend — multi-channel independence', () => {
    it('should allow email enabled but SMS disabled for same user', () => {
      service.createPreferences({
        userId: 'user-1',
        emailEnabled: true,
        channelPreferences: {
          sms: { enabled: false, categories: ALL_NOTIFICATION_CATEGORIES },
        },
      });
      expect(service.shouldSend('email', 'user-1', 'order-confirmation')).toBe(true);
      expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(false);
    });

    it('should allow different categories per channel', () => {
      service.createPreferences({
        userId: 'user-1',
        emailCategories: ALL_NOTIFICATION_CATEGORIES,
        channelPreferences: {
          sms: { enabled: true, categories: ['order-confirmation'] },
          webhook: { enabled: true, categories: ['order-status-update'] },
        },
      });

      expect(service.shouldSend('email', 'user-1', 'welcome')).toBe(true);
      expect(service.shouldSend('sms', 'user-1', 'welcome')).toBe(false);
      expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(true);
      expect(service.shouldSend('webhook', 'user-1', 'order-status-update')).toBe(true);
      expect(service.shouldSend('webhook', 'user-1', 'order-confirmation')).toBe(false);
    });
  });
});

